// ============================================================
// MOCK API DE ETAPAS (Stage) - contrato de datos
// ------------------------------------------------------------
// Este nodo SIMULA la respuesta del ERP. Imita la forma real de
// la tabla de etapas del ERP para que, cuando exista la API real,
// solo haya que cambiar STAGES_SYNC_WEBHOOK_URL en el backend de
// Twenty (el mapper mapWebhookResponseToStageOptions NO se toca).
//
// Forma del ERP (campos relevantes de la tabla de etapas):
//   id              bigint  -> identificador estable de la etapa
//   nombre          string  -> nombre visible de la etapa
//   descripcion     string  -> informativo (no se usa en el select)
//   es_etapa_cierre 0|1     -> marca la etapa ganada / de cierre
//
// El backend de Twenty mapea cada etapa a una opcion del SELECT asi:
//   value    <- STAGE_<id>   (clave interna; prefijo STAGE_ porque Twenty exige
//                             UPPER_CASE snake_case y un enum GraphQL no puede empezar con digito)
//   label    <- nombre       (texto visible en la UI)
//   color    <- generado por posicion (el ERP no manda color)
//   position <- orden del array
//   id       <- uuid v4 generado por el backend
// ============================================================

return [
  {
    json: {
      stages: [
        { id: 1, nombre: 'Contactar cliente', descripcion: 'Primer contacto con el prospecto', es_etapa_cierre: 0 },
        { id: 2, nombre: 'Calificacion',      descripcion: 'Validar interes y presupuesto',     es_etapa_cierre: 0 },
        { id: 3, nombre: 'Propuesta',         descripcion: 'Propuesta enviada',                 es_etapa_cierre: 0 },
        { id: 4, nombre: 'Negociacion',       descripcion: 'Negociacion en curso',              es_etapa_cierre: 0 },
        { id: 5, nombre: 'Cerrado ganado',    descripcion: 'Oportunidad ganada',                es_etapa_cierre: 1 },
      ],
    },
  },
];
